#include <iostream>
#include <unordered_map>
#include <vector>
#include <cmath>

double new21Game(int n, int k, int maxPts) {
    double prob = 1.0;
    double sum = 0.0;

    // Calculate the sum of probabilities
    for (int i = 1; i <= maxPts; i++) {
        sum += pow(2.0, (double)(n - k + 1) / i);
    }

    // Calculate the probability
    prob = 1.0 / sum;

    return prob;
}
